class Solution:
    def getMinSwaps(self, num, k):
        target = list(num)
        for _ in range(k):
            i = len(target) - 2
            while i >= 0 and target[i] >= target[i + 1]:
                i -= 1
            j = len(target) - 1
            while target[j] <= target[i]:
                j -= 1
            target[i], target[j] = target[j], target[i]
            target[i + 1:] = target[i + 1:][::-1]
        cur = list(num)
        swaps = 0
        n = len(cur)
        for i in range(n):
            if cur[i] == target[i]:
                continue
            j = i + 1
            while cur[j] != target[i]:
                j += 1
            while j > i:
                cur[j], cur[j - 1] = cur[j - 1], cur[j]
                j -= 1
                swaps += 1
        return swaps

