var getMinSwaps = function(num, k) {
    const target = num.split('');
    for (let t = 0; t < k; t++) {
        let i = target.length - 2;
        while (i >= 0 && target[i] >= target[i + 1]) i--;
        let j = target.length - 1;
        while (target[j] <= target[i]) j--;
        [target[i], target[j]] = [target[j], target[i]];
        let lo = i + 1, hi = target.length - 1;
        while (lo < hi) { [target[lo], target[hi]] = [target[hi], target[lo]]; lo++; hi--; }
    }
    const cur = num.split('');
    let swaps = 0;
    const n = cur.length;
    for (let i = 0; i < n; i++) {
        if (cur[i] === target[i]) continue;
        let j = i + 1;
        while (cur[j] !== target[i]) j++;
        while (j > i) {
            [cur[j], cur[j - 1]] = [cur[j - 1], cur[j]];
            j--;
            swaps++;
        }
    }
    return swaps;
};
